const v = $('Prepare All Client and Message Variables').item.json;

const today        = new Date();
const todayMMDD    = String(today.getMonth()+1).padStart(2,'0') + '-' + String(today.getDate()).padStart(2,'0');
const birthdayMMDD = new Date(v['Client Birthday']).toISOString().slice(5,10);
const isBirthday   = v['Is Birthday Today'] === true || v['Is Birthday Today'] === 'true';
const isPremium    = v['Is Premium Client'] === true || v['Is Premium Client'] === 'true';
const age          = parseInt(v['Client Age']) || 35;
const risk         = (v['Risk Profile'] || 'moderate').toLowerCase();

const birthdayByAge = {
  young: [
    { suggestion: "begin a small monthly SIP in an index fund", instrument: "Index Fund SIP", why: "Starting early gives the power of compounding — even a small amount today becomes a life-changing sum by the time you celebrate your next big milestone." },
    { suggestion: "open a Digital Gold account and start with even Rs.100", instrument: "Digital Gold", why: "Gold has been a symbol of wealth and celebration for generations — owning even a little on your birthday is a tradition that holds value forever." },
    { suggestion: "start a Recurring Deposit in your name", instrument: "Recurring Deposit", why: "A simple, risk-free way to build a birthday fund — every year this date, you will have something beautiful growing quietly in the background." }
  ],
  mid: [
    { suggestion: "start a Sovereign Gold Bond (SGB) in your name", instrument: "Sovereign Gold Bond", why: "SGBs give you gold appreciation plus annual interest — a government-backed gift to yourself that grows steadily and safely year after year." },
    { suggestion: "begin a balanced advantage mutual fund SIP today", instrument: "Balanced Advantage Fund", why: "On this milestone birthday, let your money grow with the right balance of equity and safety — a truly smart gift you give your future self." },
    { suggestion: "open a PPF account and make your first contribution", instrument: "Public Provident Fund (PPF)", why: "PPF is tax-free and guaranteed — a long-term gift to yourself that quietly compounds year after year, a tradition worth starting today." }
  ],
  senior: [
    { suggestion: "start a Senior Citizens Savings Scheme (SCSS) or a debt fund SIP", instrument: "SCSS / Debt Fund", why: "At this stage, stability and steady returns matter most — this special day is a perfect moment to lock in something secure and reliable for the years ahead." },
    { suggestion: "begin a monthly RD or fixed deposit in your name", instrument: "Fixed Deposit / RD", why: "A steady, guaranteed return that marks this birthday permanently — every renewal date will bring back the memory of today." },
    { suggestion: "invest in a conservative hybrid fund as a birthday tradition", instrument: "Conservative Hybrid Fund", why: "A gentle balance of growth and safety — ideal to start on your birthday as a tradition that honors this milestone for years to come." }
  ]
};

const anniversarySuggestions = [
  { suggestion: "start a joint Sovereign Gold Bond together", instrument: "Sovereign Gold Bond", why: "Gold bonds grow steadily and safely — starting one together on your anniversary means every year you can watch both your bond and your wealth grow side by side." },
  { suggestion: "begin a joint mutual fund SIP in both your names", instrument: "Joint Mutual Fund SIP", why: "A shared investment started on your anniversary is a beautiful tradition — a way of saying you are not just celebrating today, but building tomorrow together." },
  { suggestion: "open a joint Recurring Deposit to mark this milestone", instrument: "Joint Recurring Deposit", why: "Simple, safe and deeply symbolic — a joint RD started on your anniversary grows quietly year after year, just like your journey together." },
  { suggestion: "invest in a balanced fund together as your anniversary tradition", instrument: "Balanced Advantage Fund", why: "Every anniversary, you can look back at how this investment has grown alongside your relationship — a living, growing memory of this very day." },
  { suggestion: "start a Silver ETF together as a precious memory", instrument: "Silver ETF", why: "Silver is timeless and precious, just like the bond you share — a joint Silver ETF started today becomes a symbol you can revisit every anniversary." }
];

let pool;
if (isBirthday) {
  const group = age < 30 ? 'young' : age <= 50 ? 'mid' : 'senior';
  pool = birthdayByAge[group];
} else {
  pool = anniversarySuggestions;
}

const riskOffset = risk === 'high' ? 0 : risk === 'moderate' ? 1 : 2;
const idx = riskOffset % pool.length;
const chosen = pool[idx];

const premiumIntro = `As your trusted advisor, I would love to suggest something meaningful for this special day —`;
const normalIntro  = `Here is a little idea to make this day even more memorable —`;

return [{
  json: {
    'Client Name':            v['Client Name'],
    'Client Email':           v['Client Email'],
    'Advisor Name':           v['Advisor Name'],
    'Client Birthday':        v['Client Birthday'],
    'Client Anniversary':     v['Client Anniversary'],
    'Relationship Type':      v['Relationship Type'],
    'Client Age':             v['Client Age'],
    'Risk Profile':           v['Risk Profile'],
    'Occasion':               v['Occasion'],
    'Message Tone':           v['Message Tone'],
    'Is Premium Client':      v['Is Premium Client'],
    'Is Birthday Today':      v['Is Birthday Today'],
    'Today Date':             v['Today Date'],
    'Email Subject':          v['Email Subject'],
    'AI Prompt':              v['AI Prompt'],
    'Advisor Firm':           v['Advisor Firm'],
    'Investment Suggestion':  chosen.suggestion,
    'Investment Instrument':  chosen.instrument,
    'Investment Why':         chosen.why,
    'Investment Intro':       isPremium ? premiumIntro : normalIntro,
    'Age Group':              isBirthday ? (age < 30 ? 'Young (under 30)' : age <= 50 ? 'Mid (30-50)' : 'Senior (50+)') : 'Couple (Anniversary)'
  }
}];

